// Worked focus: cmem-effective-type-access — Access allocated and copied storage through types permitted by effective-type rules or defined character-byte paths.
/* Evidence: cmem-worked-cmem-aliasing-effective-type-provenance-3 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 6872; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


static int worked_cmem_aliasing_effective_type_provenance_3(const unsigned char *bytes, size_t length, unsigned *decoded) {
  unsigned value = 0;
  unsigned char representation[sizeof value];
  if (bytes == NULL || decoded == NULL || length != 4 || sizeof value < 4) return 0;
  representation[0] = bytes[0];
  representation[1] = bytes[1];
  representation[2] = bytes[2];
  representation[3] = bytes[3];
  value = (unsigned)representation[0] | ((unsigned)representation[1] << 8) |
          ((unsigned)representation[2] << 16) | ((unsigned)representation[3] << 24);
  *decoded = value;
  return 1;
}

int main(void) {
  unsigned char bytes[4] = { 6u, 0u, 0u, 0u };
  unsigned value = 0u;
  int rejected = worked_cmem_aliasing_effective_type_provenance_3(bytes, 3, &value);
  int accepted = worked_cmem_aliasing_effective_type_provenance_3(bytes, 4, &value);
  int invariant = !rejected && accepted && value == 6u;
  printf("decode value=%u invariant=%d\n", value, invariant);
  return invariant ? 0 : 1;
}

